import '../apply/config_apply_flow_model.dart';
import 'config_draft_edit_value.dart';
import 'config_field_presentation.dart';

class ConfigDraftSession {
  const ConfigDraftSession({this.draftValues = const {}, this.editingField});

  final Map<String, Object?> draftValues;
  final String? editingField;

  bool isEditing(ConfigFieldPresentation field) => editingField == field.path;

  String editInitialValueFor(ConfigFieldPresentation field) {
    if (field.obscureText || !draftValues.containsKey(field.path)) {
      return field.editInitialValue;
    }
    return configDraftEditInitialValue(draftValues[field.path]);
  }

  ConfigDraftSession beginEditing(ConfigFieldPresentation field) {
    return ConfigDraftSession(
      draftValues: Map.unmodifiable(draftValues),
      editingField: field.path,
    );
  }

  ConfigDraftSession cancelEditing() {
    return ConfigDraftSession(draftValues: Map.unmodifiable(draftValues));
  }

  ConfigDraftSession stageEdit(ConfigFieldPresentation field, String rawText) {
    final value = field.coerceEditValue(rawText);
    final nextDraft = Map<String, Object?>.from(draftValues);
    if (field.clearsDraftFor(value)) {
      nextDraft.remove(field.path);
    } else {
      nextDraft[field.path] = value;
    }
    return ConfigDraftSession(draftValues: Map.unmodifiable(nextDraft));
  }

  ConfigDraftSession clearApplied(ConfigApplyFlowModel flow) {
    if (!flow.hasPendingChanges) return this;
    final nextDraft = Map<String, Object?>.from(draftValues);
    for (final change in flow.changes) {
      nextDraft.remove(change.path);
    }
    return ConfigDraftSession(
      draftValues: Map.unmodifiable(nextDraft),
      editingField: editingField,
    );
  }
}

import 'config_draft_edit_value.dart';

void main() {
  reEditingAStagedNonSecretDraftUsesTheStagedValue();
}

void reEditingAStagedNonSecretDraftUsesTheStagedValue() {
  final initialValue = configDraftEditInitialValue('new name');

  _expect(
    initialValue == 'new name',
    're-editing a staged draft should show the staged value instead of the persisted value',
  );
}

void _expect(bool condition, String message) {
  if (!condition) throw StateError(message);
}

import 'config_form_field_type.dart';

Object? coerceConfigEditValue({
  required String raw,
  required ConfigFormFieldType type,
  required bool isSecret,
}) {
  final text = raw.trim();
  if (isSecret) return text;
  return switch (type) {
    ConfigFormFieldType.number => num.tryParse(text) ?? raw,
    ConfigFormFieldType.integer => int.tryParse(text) ?? raw,
    ConfigFormFieldType.boolean => coerceBooleanEditValue(text) ?? raw,
    ConfigFormFieldType.string => raw,
    ConfigFormFieldType.secret => text,
  };
}

bool? coerceBooleanEditValue(String text) {
  return switch (text.toLowerCase()) {
    'true' => true,
    'false' => false,
    _ => null,
  };
}

import 'config_form_model.dart';

void main() {
  preservesUnrecognizedBooleanEditTextForValidation();
  coercesRecognizedBooleanEditTextCaseInsensitively();
  preservesFractionalIntegerEditTextForValidation();
  readsCamelCaseSchemaRiskAndConfirmationFields();
}

void preservesUnrecognizedBooleanEditTextForValidation() {
  final row = _row(type: ConfigFormFieldType.boolean, rawValue: false);

  final result = row.coerceEditValue('maybe');

  _expect(
    result == 'maybe',
    'invalid boolean edit text should be preserved for validation instead of silently becoming false',
  );
}

void coercesRecognizedBooleanEditTextCaseInsensitively() {
  final row = _row(type: ConfigFormFieldType.boolean, rawValue: false);

  _expect(row.coerceEditValue(' TRUE ') == true, 'TRUE should coerce to true');
  _expect(
    row.coerceEditValue(' false ') == false,
    'false should coerce to false',
  );
}

void preservesFractionalIntegerEditTextForValidation() {
  final row = _row(type: ConfigFormFieldType.integer, rawValue: 1);

  final result = row.coerceEditValue('1.5');

  _expect(
    result == '1.5',
    'fractional text entered for an integer field should be preserved for validation instead of coerced to a number',
  );
}

void readsCamelCaseSchemaRiskAndConfirmationFields() {
  final form = ConfigFormModel.fromSchema(
    schema: {
      'fields': [
        {
          'path': 'server.port',
          'type': 'integer',
          'label': 'Server port',
          'restartRequired': true,
          'requiresConfirmation': true,
          'riskLevel': 'Medium',
        },
      ],
    },
    values: {'server.port': 8080},
  );

  final row = form.rows.single;

  _expect(
    row.restartRequired,
    'camelCase restartRequired schema flag should require restart',
  );
  _expect(
    row.requiresConfirmation,
    'camelCase requiresConfirmation schema flag should require confirmation',
  );
  _expect(
    row.riskLevel == 'medium',
    'camelCase riskLevel schema field should be normalized to lowercase',
  );
}

ConfigFormRow _row({required ConfigFormFieldType type, Object? rawValue}) {
  return ConfigFormRow(
    field: 'feature.enabled',
    label: 'Feature enabled',
    type: type,
    required: false,
    restartRequired: false,
    riskLevel: 'low',
    requiresConfirmation: false,
    rawValue: rawValue,
  );
}

void _expect(bool condition, String message) {
  if (!condition) throw StateError(message);
}

import '../../../core/protocol/navivox_json.dart';
import '../shared/config_value_display.dart';
import 'config_edit_value_coercion.dart';
import 'config_form_field_type.dart';
import 'config_wire_fields.dart';

export 'config_form_field_type.dart';

class ConfigFormModel {
  const ConfigFormModel({required this.rows, required this.sections});

  factory ConfigFormModel.fromSchema({
    required Map<String, Object?>? schema,
    required Map<String, Object?> values,
  }) {
    final rawFields = schema?['fields'];
    if (rawFields is! List) {
      return const ConfigFormModel(rows: [], sections: []);
    }

    final rows = <ConfigFormRow>[];
    for (final raw in rawFields) {
      if (raw is! Map) continue;
      final field = configWireStringFromAliases(raw, const [
        'path',
        'key',
        'name',
      ]);
      if (field == null || field.isEmpty) continue;
      final type = ConfigFormFieldType.fromWire(raw['type']?.toString());
      final secret =
          raw['secret'] == true || type == ConfigFormFieldType.secret;
      final riskLevel = _fieldRiskLevel(raw);
      rows.add(
        ConfigFormRow(
          field: field,
          label: _fieldLabel(raw, field),
          type: secret ? ConfigFormFieldType.secret : type,
          required: _fieldBool(raw, const ['required']),
          restartRequired:
              _fieldBool(raw, const ['restart_required']) ||
              raw['reload']?.toString().contains('restart') == true,
          riskLevel: riskLevel,
          requiresConfirmation:
              _fieldBool(raw, const ['requires_confirmation']) ||
              riskLevel == 'high',
          rawValue: values[field],
          allowedValues: _stringList(raw['allowed']),
          actions: _stringList(raw['actions']),
          reloadMode: configWireString(raw['reload']) ?? '',
        ),
      );
    }
    return ConfigFormModel(
      rows: rows,
      sections: _buildSections(schema?['sections'], rows),
    );
  }

  final List<ConfigFormRow> rows;
  final List<ConfigFormSection> sections;

  ConfigSectionSelection selectSection(String? sectionId) {
    final id = sectionId?.trim();
    if (id == null || id.isEmpty) {
      return ConfigSectionSelection(sections: sections);
    }
    for (final section in sections) {
      if (section.id == id) {
        return ConfigSectionSelection(sections: [section], requestedId: id);
      }
    }
    return ConfigSectionSelection(
      sections: const [],
      requestedId: id,
      missingId: id,
    );
  }

  static List<ConfigFormSection> _buildSections(
    Object? rawSections,
    List<ConfigFormRow> rows,
  ) {
    if (rows.isEmpty) return const [];
    if (rawSections is! List) {
      return [ConfigFormSection.general(rows: rows)];
    }

    final rowsByField = {for (final row in rows) row.field: row};
    final usedFields = <String>{};
    final sections = <ConfigFormSection>[];

    for (final raw in rawSections) {
      if (raw is! Map) continue;
      final sectionRows = <ConfigFormRow>[];
      for (final field in _sectionFieldRefs(raw['fields'])) {
        final row = rowsByField[field];
        if (row == null || usedFields.contains(row.field)) continue;
        sectionRows.add(row);
        usedFields.add(row.field);
      }
      if (sectionRows.isEmpty) continue;
      final id =
          configWireString(raw['id']) ?? 'section-${sections.length + 1}';
      sections.add(
        ConfigFormSection(
          id: id,
          label: configWireString(raw['label']) ?? id,
          description: configWireString(raw['description']),
          rows: sectionRows,
        ),
      );
    }

    final otherRows = rows
        .where((row) => !usedFields.contains(row.field))
        .toList(growable: false);
    if (otherRows.isNotEmpty) {
      sections.add(
        sections.isEmpty
            ? ConfigFormSection.general(rows: otherRows)
            : ConfigFormSection.other(rows: otherRows),
      );
    }
    return sections;
  }

  static String _fieldLabel(Map raw, String fallback) {
    return configWireStringFromAliases(raw, const ['label', 'title']) ??
        fallback;
  }

  static bool _fieldBool(Map raw, Iterable<String> aliases) {
    return configWireValueFromAliases(raw, aliases) == true;
  }

  static String _fieldRiskLevel(Map raw) {
    return configWireStringFromAliases(raw, const ['risk_level'])
            ?.toLowerCase() ??
        'low';
  }

  static List<String> _stringList(Object? raw) {
    return navivoxStringListFromJson(raw);
  }

  static List<String> _sectionFieldRefs(Object? rawFields) {
    if (rawFields is! List) return const [];
    final refs = <String>[];
    for (final raw in rawFields) {
      final text = raw is Map
          ? configWireStringFromAliases(raw, const ['path', 'key', 'name'])
          : configWireString(raw);
      if (text != null) refs.add(text);
    }
    return refs;
  }
}

class ConfigSectionSelection {
  const ConfigSectionSelection({
    required this.sections,
    this.requestedId,
    this.missingId,
  });

  final List<ConfigFormSection> sections;
  final String? requestedId;
  final String? missingId;

  bool get isFiltered => requestedId != null;

  bool get isMissing => missingId != null;
}

class ConfigFormSection {
  const ConfigFormSection({
    required this.id,
    required this.label,
    required this.rows,
    this.description,
  });

  const ConfigFormSection.general({required this.rows})
    : id = 'general',
      label = 'General config',
      description = null;

  const ConfigFormSection.other({required this.rows})
    : id = 'other',
      label = 'Other config',
      description = null;

  final String id;
  final String label;
  final String? description;
  final List<ConfigFormRow> rows;
}

class ConfigFormRow {
  const ConfigFormRow({
    required this.field,
    required this.label,
    required this.type,
    required this.required,
    required this.restartRequired,
    required this.riskLevel,
    required this.requiresConfirmation,
    required this.rawValue,
    this.allowedValues = const [],
    this.actions = const [],
    this.reloadMode = '',
  });

  final String field;
  final String label;
  final ConfigFormFieldType type;
  final bool required;
  final bool restartRequired;
  final String riskLevel;
  final bool requiresConfirmation;
  final Object? rawValue;
  final List<String> allowedValues;
  final List<String> actions;
  final String reloadMode;

  bool get isSecret => type == ConfigFormFieldType.secret;

  Object? get plainValue => _plainValue(rawValue);

  String get displayValue {
    if (isSecret) return configSecretDisplayValue(rawValue);
    return configDisplayValue(_plainValue(rawValue));
  }

  String get editInitialValue {
    if (isSecret) return '';
    final value = _plainValue(rawValue);
    return value == null ? '' : '$value';
  }

  Object? coerceEditValue(String raw) =>
      coerceConfigEditValue(raw: raw, type: type, isSecret: isSecret);

  static Object? _plainValue(Object? rawValue) {
    if (rawValue is Map && rawValue.containsKey('value')) {
      return rawValue['value'];
    }
    return rawValue;
  }
}

import '../form/config_form_model.dart';
import '../form/config_wire_fields.dart';
import '../form/wire/config_form_wire_contract.dart';
import '../shared/config_value_display.dart';

class ConfigApplyFlowModel {
  const ConfigApplyFlowModel({required this.changes});

  factory ConfigApplyFlowModel.fromDraft({
    required ConfigFormModel form,
    required Map<String, Object?> draftValues,
    Map<String, Object?>? validationSnapshot,
  }) {
    final validation = ConfigValidationState.fromSnapshot(validationSnapshot);
    final changes = <ConfigDraftChange>[];
    for (final row in form.rows) {
      if (!draftValues.containsKey(row.field)) continue;
      final change = ConfigDraftChange.fromRow(
        row,
        draftValues[row.field],
        validation.messagesFor(row.field),
      );
      if (change != null) changes.add(change);
    }
    return ConfigApplyFlowModel(changes: changes);
  }

  final List<ConfigDraftChange> changes;

  bool get hasPendingChanges => changes.isNotEmpty;

  bool get hasInvalidChanges => changes.any((change) => change.isInvalid);

  bool get canApply => hasPendingChanges && !hasInvalidChanges;

  bool get requiresConfirmation =>
      changes.any((change) => change.requiresConfirmation);

  List<String> validationMessagesFor(String path) {
    return changes
        .where((change) => change.path == path)
        .expand((change) => change.validationMessages)
        .toList(growable: false);
  }
}

enum ConfigDraftValidationState { unknown, valid, invalid }

class ConfigDraftChange {
  const ConfigDraftChange({
    required this.path,
    required this.label,
    required this.oldDisplayValue,
    required this.newDisplayValue,
    required this.applyValue,
    required this.isSecret,
    required this.requiresConfirmation,
    required this.restartRequired,
    this.validationMessages = const [],
  });

  static ConfigDraftChange? fromRow(
    ConfigFormRow row,
    Object? draftValue,
    List<String> validationMessages,
  ) {
    if (row.isSecret) {
      final secret = configWireString(draftValue) ?? '';
      if (secret.isEmpty) return null;
      return ConfigDraftChange(
        path: row.field,
        label: row.label,
        oldDisplayValue: row.displayValue,
        newDisplayValue: configSecretWillBeUpdatedLabel,
        applyValue: secret,
        isSecret: true,
        requiresConfirmation: row.requiresConfirmation,
        restartRequired: row.restartRequired,
        validationMessages: validationMessages,
      );
    }

    if (_sameValue(row.plainValue, draftValue)) return null;
    return ConfigDraftChange(
      path: row.field,
      label: row.label,
      oldDisplayValue: _displayValue(row.plainValue),
      newDisplayValue: _displayValue(draftValue),
      applyValue: draftValue,
      isSecret: false,
      requiresConfirmation: row.requiresConfirmation,
      restartRequired: row.restartRequired,
      validationMessages: validationMessages,
    );
  }

  final String path;
  final String label;
  final String oldDisplayValue;
  final String newDisplayValue;
  final Object? applyValue;
  final bool isSecret;
  final bool requiresConfirmation;
  final bool restartRequired;
  final List<String> validationMessages;

  String get summaryLabel => '$label: $oldDisplayValue -> $newDisplayValue';

  ConfigDraftValidationState get validationState => validationMessages.isEmpty
      ? ConfigDraftValidationState.unknown
      : ConfigDraftValidationState.invalid;

  bool get isInvalid => validationState == ConfigDraftValidationState.invalid;

  static bool _sameValue(Object? left, Object? right) => left == right;

  static String _displayValue(Object? value) => configDisplayValue(value);
}

class ConfigValidationState {
  const ConfigValidationState(this._messagesByPath);

  factory ConfigValidationState.fromSnapshot(Map<String, Object?>? snapshot) {
    final messages = <String, List<String>>{};
    if (snapshot == null) return ConfigValidationState(messages);
    _addValidationErrorList(
      messages,
      configWireValueFromAliases(snapshot, const ['validation_errors']),
    );
    _addValidationErrorList(messages, snapshot['errors']);
    _addFieldErrorMap(
      messages,
      configWireValueFromAliases(snapshot, const ['field_errors']),
    );
    return ConfigValidationState(messages);
  }

  final Map<String, List<String>> _messagesByPath;

  List<String> messagesFor(String path) {
    return List.unmodifiable(_messagesByPath[path] ?? const []);
  }

  static void _addValidationErrorList(
    Map<String, List<String>> target,
    Object? rawErrors,
  ) {
    if (rawErrors is! List) return;
    for (final raw in rawErrors) {
      if (raw is! Map) continue;
      final path = configFormValidationPathFromWire(raw);
      final message = configFormValidationMessageFromWire(raw);
      if (path == null || message == null) continue;
      target.putIfAbsent(path, () => []).add(message);
    }
  }

  static void _addFieldErrorMap(
    Map<String, List<String>> target,
    Object? rawErrors,
  ) {
    if (rawErrors is! Map) return;
    for (final entry in rawErrors.entries) {
      final path = configWireString(entry.key);
      if (path == null) continue;
      final messages = _messagesFrom(entry.value);
      if (messages.isEmpty) continue;
      target.putIfAbsent(path, () => []).addAll(messages);
    }
  }

  static List<String> _messagesFrom(Object? raw) {
    if (raw is List) {
      return raw.map(_messageFrom).nonNulls.toList(growable: false);
    }
    final message = configWireString(raw);
    return message == null ? const [] : [message];
  }

  static String? _messageFrom(Object? raw) => configWireString(raw);
}

import '../form/config_form_model.dart';
import 'config_apply_flow_model.dart';

void main() {
  attachesValidationErrorListMessagesToDraftChanges();
  attachesCamelCaseValidationSnapshotMessagesToDraftChanges();
}

void attachesValidationErrorListMessagesToDraftChanges() {
  final form = ConfigFormModel.fromSchema(
    schema: {
      'fields': [
        {
          'path': 'feature.enabled',
          'type': 'boolean',
          'label': 'Feature enabled',
        },
      ],
    },
    values: {'feature.enabled': false},
  );

  final flow = ConfigApplyFlowModel.fromDraft(
    form: form,
    draftValues: {'feature.enabled': 'maybe'},
    validationSnapshot: {
      'validation_errors': [
        {'path': 'feature.enabled', 'message': 'Expected a boolean.'},
      ],
    },
  );

  _expect(
    flow.hasInvalidChanges,
    'validation errors should mark the draft invalid',
  );
  _expect(
    flow.validationMessagesFor('feature.enabled').single ==
        'Expected a boolean.',
    'validation error message should be attached to its field path',
  );
}

void attachesCamelCaseValidationSnapshotMessagesToDraftChanges() {
  final form = ConfigFormModel.fromSchema(
    schema: {
      'fields': [
        {
          'path': 'feature.enabled',
          'type': 'boolean',
          'label': 'Feature enabled',
        },
      ],
    },
    values: {'feature.enabled': false},
  );

  final flow = ConfigApplyFlowModel.fromDraft(
    form: form,
    draftValues: {'feature.enabled': 'maybe'},
    validationSnapshot: {
      'validationErrors': [
        {'field': 'feature.enabled', 'detail': 'Expected a boolean.'},
      ],
      'fieldErrors': {
        'feature.enabled': ['Still not a boolean.'],
      },
    },
  );

  _expect(
    flow.hasInvalidChanges,
    'camelCase validation snapshots should mark the draft invalid',
  );
  _expect(
    flow.validationMessagesFor('feature.enabled').join('|') ==
        'Expected a boolean.|Still not a boolean.',
    'camelCase validation snapshot messages should be attached to their field path',
  );
}

void _expect(bool condition, String message) {
  if (!condition) throw StateError(message);
}

import '../serialization/navivox_json.dart';

/// Shared helpers for loose config-schema/validation wire maps.
///
/// Gormes config payloads may identify fields with related aliases depending on
/// whether the source is schema rows, validation errors, or section references.
/// These helpers keep alias lookup and non-empty string coercion consistent
/// across gateway protocol models and UI form models without broadening each
/// call site's accepted aliases.
String? configWireString(Object? raw) => navivoxOptionalStringFromJson(raw);

Object? configWireValueFromAliases(Map raw, Iterable<String> aliases) {
  for (final alias in aliases) {
    if (raw.containsKey(alias)) return raw[alias];
  }

  final normalizedAliases = {
    for (final alias in aliases) _configNormalizeWireFieldName(alias),
  };
  for (final entry in raw.entries) {
    if (normalizedAliases.contains(
      _configNormalizeWireFieldName('${entry.key}'),
    )) {
      return entry.value;
    }
  }
  return null;
}

String? configWireStringFromAliases(Map raw, Iterable<String> aliases) {
  return configWireString(configWireValueFromAliases(raw, aliases));
}

String _configNormalizeWireFieldName(String value) =>
    value.toLowerCase().replaceAll('_', '');

import 'dart:convert';

import '../../../../core/protocol/navivox_endpoint_uri.dart';
import '../../../../core/protocol/navivox_json.dart';
import '../../../../core/protocol/navivox_pairing_descriptor.dart';
import '../../models/connection_import.dart';

class ConnectionImportParser {
  const ConnectionImportParser();

  SetupQrImageImport? parsePayload(String payload) {
    final text = payload.trim();
    if (text.isEmpty) return null;

    final jsonResult = _parseQrJsonPayload(text);
    if (jsonResult != null && jsonResult.hasValues) return jsonResult;

    final copiedUriPayload = _copiedUriPayload(text);
    if (copiedUriPayload != null) {
      if (_isCorePairingDescriptorUri(copiedUriPayload.uri)) {
        return _parseCorePairingDescriptor(
          copiedUriPayload.text,
          copiedUriPayload.uri,
        );
      }

      final uriImport = _importFromGenericUri(copiedUriPayload.uri);
      if (uriImport != null) return uriImport;
    }

    return _importFromSharedText(text);
  }

  _CopiedUriPayload? _copiedUriPayload(String text) {
    final copiedUrl = _trimCopiedUrlTrailingPunctuation(text);
    final uri = Uri.tryParse(copiedUrl);
    if (uri == null || !uri.hasScheme) return null;
    return _CopiedUriPayload(text: copiedUrl, uri: uri);
  }

  SetupQrImageImport? _parseCorePairingDescriptor(String text, Uri uri) {
    if (uri.scheme != 'navivox' || uri.host != 'connect') return null;
    try {
      final descriptor = NavivoxPairingDescriptor.parse(text);
      return SetupQrImageImport(
        baseUrl: descriptor.baseUri.toString(),
        token: descriptor.token,
        webSocketUrl: descriptor.webSocketUri.toString(),
        serverId: descriptor.serverId,
        profileId: descriptor.profileId,
      );
    } on FormatException {
      return null;
    }
  }

  SetupQrImageImport? _parseQrJsonPayload(String text) {
    Object? decoded;
    try {
      decoded = jsonDecode(text);
    } catch (_) {
      return null;
    }
    if (decoded is! Map) return null;

    return _bestImportFromCandidateMaps(_jsonCandidateMaps(decoded));
  }
}

SetupQrImageImport? parseNavivoxConnectionImportPayload(String payload) =>
    const ConnectionImportParser().parsePayload(payload);

class _CopiedUriPayload {
  const _CopiedUriPayload({required this.text, required this.uri});

  final String text;
  final Uri uri;
}

bool _isCorePairingDescriptorUri(Uri uri) =>
    uri.scheme == 'navivox' && uri.host == 'connect';

Iterable<_JsonConnectionImportFields> _jsonCandidateMaps(
  Map<dynamic, dynamic> decoded,
) sync* {
  final entries = decoded['entries'];
  if (entries is! List) {
    yield _JsonConnectionImportFields(
      fields: decoded,
      hasExplicitConnectionFields: true,
    );
    return;
  }

  var yieldedEntry = false;
  for (final fields in _entryCandidateMaps(decoded, entries)) {
    yieldedEntry = true;
    yield fields;
  }
  if (!yieldedEntry) {
    yield _JsonConnectionImportFields(
      fields: decoded,
      hasExplicitConnectionFields: true,
    );
  }
}

Iterable<_JsonConnectionImportFields> _entryCandidateMaps(
  Map<dynamic, dynamic> decoded,
  List<dynamic> entries,
) sync* {
  for (final entry in entries) {
    if (entry is! Map) continue;
    yield _JsonConnectionImportFields(
      fields: _entryFieldsWithJsonDefaults(decoded, entry),
      hasExplicitConnectionFields: _hasNonBlankJsonConnectionField(entry),
    );
  }
}

class _JsonConnectionImportFields {
  const _JsonConnectionImportFields({
    required this.fields,
    required this.hasExplicitConnectionFields,
  });

  final Map<dynamic, dynamic> fields;

  // Entries may inherit top-level credentials, but metadata-only entries should
  // not outrank entries that carry their own endpoint/token provenance.
  final bool hasExplicitConnectionFields;
}

Map<dynamic, dynamic> _entryFieldsWithJsonDefaults(
  Map<dynamic, dynamic> defaults,
  Map<dynamic, dynamic> entry,
) {
  final fields = Map<dynamic, dynamic>.of(defaults)..remove('entries');
  _removeDefaultJsonAliasesOverriddenByEntry(fields, entry);
  for (final entryField in entry.entries) {
    if (_isBlankJsonValue(entryField.value)) continue;
    fields[entryField.key] = entryField.value;
  }
  return fields;
}

void _removeDefaultJsonAliasesOverriddenByEntry(
  Map<dynamic, dynamic> fields,
  Map<dynamic, dynamic> entry,
) {
  for (final aliases in _jsonConnectionImportFieldAliasGroups) {
    if (navivoxFirstStringFieldFromJson(entry, aliases) == null) continue;
    for (final alias in aliases) {
      fields.remove(alias);
    }
  }
}

bool _hasNonBlankJsonConnectionField(Map<dynamic, dynamic> fields) {
  return navivoxFirstStringFieldFromJson(fields, _tokenFieldNames) != null ||
      navivoxFirstStringFieldFromJson(fields, _baseUrlFieldNames) != null ||
      navivoxFirstStringFieldFromJson(fields, _webSocketUrlFieldNames) != null;
}

bool _isBlankJsonValue(Object? value) {
  if (value == null) return true;
  if (value is String && value.trim().isEmpty) return true;
  return false;
}

SetupQrImageImport? _bestImportFromCandidateMaps(
  Iterable<_JsonConnectionImportFields> candidateMaps,
) {
  _ConnectionImportCandidate? bestCandidate;
  for (final candidateFields in candidateMaps) {
    final candidate = _connectionImportCandidateFromFields(
      candidateFields.fields,
      hasExplicitConnectionFields: candidateFields.hasExplicitConnectionFields,
    );
    if (candidate == null) continue;
    bestCandidate = _richerConnectionImportCandidate(
      currentBest: bestCandidate,
      candidate: candidate,
    );
  }
  return bestCandidate?.toImport();
}

_ConnectionImportCandidate? _connectionImportCandidateFromFields(
  Map<dynamic, dynamic> fields, {
  String? fallbackBaseUrl,
  bool hasExplicitConnectionFields = true,
}) {
  final token = navivoxFirstStringFieldFromJson(fields, _tokenFieldNames);
  final endpointFields = _connectionImportEndpointFields(fields);
  final candidate = _ConnectionImportCandidate(
    baseUrl: endpointFields.baseUrl ?? fallbackBaseUrl,
    token: token,
    webSocketUrl: endpointFields.webSocketUrl,
    serverId: navivoxFirstStringFieldFromJson(fields, _serverIdFieldNames),
    profileId: navivoxFirstStringFieldFromJson(fields, _profileIdFieldNames),
    hasExplicitConnectionFields: hasExplicitConnectionFields,
  );
  if (!candidate.hasImportValues) return null;

  return candidate;
}

_ConnectionImportEndpointFields _connectionImportEndpointFields(
  Map<dynamic, dynamic> fields,
) {
  final webSocketUrl = navivoxFirstStringFieldFromJson(
    fields,
    _webSocketUrlFieldNames,
  );
  final normalizedWebSocketUrl = _normalizeWebSocketUrl(webSocketUrl);
  return _ConnectionImportEndpointFields(
    baseUrl:
        _normalizeBaseUrl(
          navivoxFirstStringFieldFromJson(fields, _baseUrlFieldNames),
        ) ??
        _normalizeBaseUrlFromWebSocketUrl(normalizedWebSocketUrl),
    webSocketUrl: normalizedWebSocketUrl,
  );
}

class _ConnectionImportEndpointFields {
  const _ConnectionImportEndpointFields({this.baseUrl, this.webSocketUrl});

  final String? baseUrl;
  final String? webSocketUrl;
}

SetupQrImageImport? _importFromGenericUri(Uri uri) {
  return _connectionImportCandidateFromGenericUri(uri)?.toImport();
}

_ConnectionImportCandidate? _connectionImportCandidateFromGenericUri(Uri uri) {
  final candidate = _connectionImportCandidateFromFields(
    _genericUriFields(uri),
    fallbackBaseUrl: _baseUrlFromGenericUri(uri),
  );
  if (candidate != null) return candidate;
  if (uri.scheme == 'http' || uri.scheme == 'https') {
    return _ConnectionImportCandidate(baseUrl: navivoxOriginFromUri(uri));
  }
  if (_isWebSocketUri(uri)) {
    return _ConnectionImportCandidate(
      baseUrl: _webSocketUriBaseUrl(uri),
      webSocketUrl: uri.toString(),
    );
  }
  return null;
}

SetupQrImageImport? _importFromSharedText(String text) {
  final embeddedUrlCandidate = _bestGenericUrlCandidateFromSharedText(text);
  final token = _sharedTextImportToken(
    text: text,
    embeddedUrlCandidate: embeddedUrlCandidate,
  );
  if (embeddedUrlCandidate == null && token == null) return null;

  return SetupQrImageImport(
    baseUrl: embeddedUrlCandidate?.candidate.baseUrl,
    token: token,
    webSocketUrl: embeddedUrlCandidate?.candidate.webSocketUrl,
    serverId: embeddedUrlCandidate?.candidate.serverId,
    profileId: embeddedUrlCandidate?.candidate.profileId,
  );
}

String? _sharedTextImportToken({
  required String text,
  required _SharedTextEndpointCandidate? embeddedUrlCandidate,
}) {
  final candidateToken = embeddedUrlCandidate?.candidate.token;
  if (candidateToken != null) return candidateToken;

  // Keep token provenance aligned with the selected URL candidate. Tokens after
  // the selected URL are more likely to describe that endpoint than stale prose
  // tokens copied earlier in the share text. Preserve older token-before-URL
  // imports by falling back to the first token in the whole text.
  return _firstToken(
        text,
        start: embeddedUrlCandidate?.tokenSearchStart ?? 0,
        end: embeddedUrlCandidate?.tokenSearchEnd,
      ) ??
      _firstToken(text);
}

_SharedTextEndpointCandidate? _bestGenericUrlCandidateFromSharedText(
  String text,
) {
  _SharedTextEndpointCandidate? bestCandidate;
  for (final endpoint in _endpointUrls(text)) {
    final uri = Uri.tryParse(endpoint.url);
    final candidate = uri != null && uri.hasScheme
        ? _connectionImportCandidateFromGenericUri(uri)
        : _connectionImportCandidateFromFields({'base_url': endpoint.url});
    if (candidate == null) continue;
    final sharedTextCandidate = _SharedTextEndpointCandidate(
      candidate: candidate,
      tokenSearchStart: endpoint.tokenSearchStart,
      tokenSearchEnd: endpoint.tokenSearchEnd,
      hasFollowingToken:
          _firstToken(
            text,
            start: endpoint.tokenSearchStart,
            end: endpoint.tokenSearchEnd,
          ) !=
          null,
      hasConnectionPath: uri != null && _hasConnectionPath(uri),
    );
    bestCandidate = sharedTextCandidate.isRicherThan(bestCandidate)
        ? sharedTextCandidate
        : bestCandidate;
  }
  return bestCandidate;
}

Iterable<_SharedTextEndpoint> _endpointUrls(String text) sync* {
  final matches = _endpointUrlPattern.allMatches(text).toList();
  for (var index = 0; index < matches.length; index++) {
    final match = matches[index];
    final url = match.group(0);
    if (url == null) continue;
    final nextEndpointStart = index + 1 < matches.length
        ? matches[index + 1].start
        : text.length;
    yield _SharedTextEndpoint(
      url: _trimCopiedUrlTrailingPunctuation(url),
      tokenSearchStart: match.end,
      tokenSearchEnd: nextEndpointStart,
    );
  }
}

class _SharedTextEndpoint {
  const _SharedTextEndpoint({
    required this.url,
    required this.tokenSearchStart,
    required this.tokenSearchEnd,
  });

  final String url;
  final int tokenSearchStart;
  final int tokenSearchEnd;
}

class _SharedTextEndpointCandidate {
  const _SharedTextEndpointCandidate({
    required this.candidate,
    required this.tokenSearchStart,
    required this.tokenSearchEnd,
    required this.hasFollowingToken,
    required this.hasConnectionPath,
  });

  final _ConnectionImportCandidate candidate;
  final int tokenSearchStart;
  final int tokenSearchEnd;
  final bool hasFollowingToken;
  final bool hasConnectionPath;

  bool isRicherThan(_SharedTextEndpointCandidate? other) {
    if (other == null) return true;

    final rank = candidate.rank;
    final otherRank = other.candidate.rank;
    if (rank.isRicherThan(otherRank)) return true;
    if (otherRank.isRicherThan(rank)) return false;

    // When two bare URLs expose the same connection fields, bind shared-text
    // tokens to the URL whose segment actually contains the token. This avoids
    // pairing a later setup token with an earlier documentation URL.
    if (hasFollowingToken != other.hasFollowingToken) return hasFollowingToken;

    // Equal-rank metadata-only URLs can otherwise leave a docs/setup link as
    // the winner merely because it appeared first. Prefer a candidate whose path
    // uses the explicit connection route vocabulary already emitted by setup
    // links before falling back to source order.
    if (hasConnectionPath != other.hasConnectionPath) return hasConnectionPath;
    return false;
  }
}

bool _hasConnectionPath(Uri uri) {
  return uri.pathSegments.any(
    (segment) => _connectionPathSegments.contains(segment.toLowerCase()),
  );
}

const _connectionPathSegments = {'connect', 'connection', 'pair', 'pairing'};

Map<String, String> _genericUriFields(Uri uri) {
  final fields = navivoxFirstNonBlankQueryParameterValues(
    uri.queryParametersAll,
  );
  if (_isWebSocketUri(uri) &&
      navivoxFirstStringFieldFromJson(fields, _webSocketUrlFieldNames) ==
          null) {
    fields['websocket_url'] = uri.toString();
  }
  return fields;
}

String? _baseUrlFromGenericUri(Uri uri) {
  return switch (uri.scheme) {
    'http' || 'https' => navivoxOriginFromUri(uri),
    'ws' || 'wss' => _webSocketUriBaseUrl(uri),
    _ => null,
  };
}

bool _isWebSocketUri(Uri uri) => uri.scheme == 'ws' || uri.scheme == 'wss';

String? _webSocketUriBaseUrl(Uri uri) {
  try {
    return navivoxHttpBaseUrlFromEndpointUri(uri);
  } on FormatException {
    return null;
  }
}

class _ConnectionImportCandidate {
  const _ConnectionImportCandidate({
    this.baseUrl,
    this.token,
    this.webSocketUrl,
    this.serverId,
    this.profileId,
    this.hasExplicitConnectionFields = true,
  });

  final String? baseUrl;
  final String? token;
  final String? webSocketUrl;
  final String? serverId;
  final String? profileId;
  final bool hasExplicitConnectionFields;

  bool get hasImportValues => baseUrl != null || token != null;

  bool get hasCompleteConnection => baseUrl != null && token != null;

  _ConnectionImportCandidateRank get rank => _ConnectionImportCandidateRank(
    isCompleteConnection: hasCompleteConnection,
    hasExplicitConnectionFields: hasExplicitConnectionFields,
    fieldScore: _fieldScore,
  );

  int get _fieldScore {
    var result = 0;
    if (baseUrl != null) result += 2;
    if (token != null) result += 2;
    if (webSocketUrl != null) result += 1;
    if (serverId != null) result += 1;
    if (profileId != null) result += 1;
    return result;
  }

  bool isRicherThan(_ConnectionImportCandidate? other) {
    return other == null || rank.isRicherThan(other.rank);
  }

  SetupQrImageImport toImport() {
    return SetupQrImageImport(
      baseUrl: baseUrl,
      token: token,
      webSocketUrl: webSocketUrl,
      serverId: serverId,
      profileId: profileId,
    );
  }
}

class _ConnectionImportCandidateRank {
  const _ConnectionImportCandidateRank({
    required this.isCompleteConnection,
    required this.hasExplicitConnectionFields,
    required this.fieldScore,
  });

  final bool isCompleteConnection;
  final bool hasExplicitConnectionFields;
  final int fieldScore;

  bool isRicherThan(_ConnectionImportCandidateRank other) {
    if (isCompleteConnection != other.isCompleteConnection) {
      return isCompleteConnection;
    }
    if (hasExplicitConnectionFields != other.hasExplicitConnectionFields) {
      return hasExplicitConnectionFields;
    }
    return fieldScore > other.fieldScore;
  }
}

_ConnectionImportCandidate _richerConnectionImportCandidate({
  required _ConnectionImportCandidate? currentBest,
  required _ConnectionImportCandidate candidate,
}) {
  // A complete baseUrl+token candidate can still be lower-fidelity than a later
  // complete candidate carrying provenance metadata. Selection therefore scores
  // all candidates instead of short-circuiting at the first complete import.
  return candidate.isRicherThan(currentBest) ? candidate : currentBest!;
}

const _tokenFieldNames = [
  'token',
  'pairing_token',
  'pairingToken',
  'auth_token',
  'rest_token',
  'restToken',
];
const _webSocketUrlFieldNames = [
  'websocket_url',
  'websocketUrl',
  'ws_url',
  'wsUrl',
];
const _baseUrlFieldNames = ['base_url', 'baseUrl', 'gateway_url', 'url'];
const _serverIdFieldNames = ['server_id', 'serverId'];
const _profileIdFieldNames = ['profile_id', 'profileId'];
const _jsonConnectionImportFieldAliasGroups = [
  _tokenFieldNames,
  _webSocketUrlFieldNames,
  _baseUrlFieldNames,
  _serverIdFieldNames,
  _profileIdFieldNames,
];

// Shared-text imports accept the same generic endpoint schemes as direct URL
// imports. Keeping the regex explicit prevents HTTP-only drift from silently
// dropping websocket endpoints embedded in prose.
final _endpointUrlPattern = RegExp(r'(?:https?|wss?)://\S+');

String _trimCopiedUrlTrailingPunctuation(String url) {
  var end = url.length;
  while (end > 0 && _copiedUrlTrailingPunctuation.contains(url[end - 1])) {
    end--;
  }
  return url.substring(0, end);
}

// Plain-text shares often end a copied URL with sentence/list punctuation or
// markdown/code delimiters. Keep this list explicit because these characters
// otherwise become part of the parsed origin when the shared URL has no path,
// or part of a query token when the URL carries connection credentials.
const _copiedUrlTrailingPunctuation = '.,;:!?)]}>"\'`';

String? _firstToken(String text, {int start = 0, int? end}) {
  final tokenSearchEnd = end ?? text.length;
  final labeledToken = _firstLabeledToken(
    text,
    start: start,
    end: tokenSearchEnd,
  );
  if (labeledToken != null) return labeledToken;

  final navivoxIndex = text.toLowerCase().indexOf('nvbx_', start);
  if (navivoxIndex < 0 || navivoxIndex >= tokenSearchEnd) return null;
  return _readTokenAt(text, navivoxIndex, end: tokenSearchEnd);
}

String? _firstLabeledToken(
  String text, {
  required int start,
  required int end,
}) {
  _LabeledTokenMatch? earliestMatch;
  for (final label in _tokenLabels) {
    final matches = RegExp(
      '${RegExp.escape(label)}\\s*[:=]',
      caseSensitive: false,
    ).allMatches(text, start).where((match) => match.start < end);
    for (final match in matches) {
      final token = _readLabeledTokenAt(text, match.end, end: end);
      if (token == null) continue;
      final candidate = _LabeledTokenMatch(start: match.start, token: token);
      if (candidate.isBefore(earliestMatch)) earliestMatch = candidate;
    }
  }
  return earliestMatch?.token;
}

class _LabeledTokenMatch {
  const _LabeledTokenMatch({required this.start, required this.token});

  final int start;
  final String token;

  bool isBefore(_LabeledTokenMatch? other) =>
      other == null || start < other.start;
}

const _tokenLabels = [
  'pairing token',
  'pairing_token',
  'pairing-token',
  'auth token',
  'auth_token',
  'auth-token',
  'token',
];

String? _readLabeledTokenAt(String text, int start, {int? end}) {
  final token = _readTokenAt(text, start, end: end);
  if (token == null || _looksLikeUrlToken(token)) return null;
  return token;
}

bool _looksLikeUrlToken(String token) =>
    RegExp(r'^[a-z][a-z0-9+.-]*://', caseSensitive: false).hasMatch(token);

String? _readTokenAt(String text, int start, {int? end}) {
  final tokenSearchEnd = end ?? text.length;
  var index = start;
  index = _skipTokenLeadingIgnoredChars(text, index, end: tokenSearchEnd);
  final tokenStart = index;
  while (index < tokenSearchEnd &&
      index < text.length &&
      _isTokenChar(text.codeUnitAt(index))) {
    index++;
  }
  if (index == tokenStart) return null;
  return _trimTokenTrailingPunctuation(text.substring(tokenStart, index));
}

int _skipTokenLeadingIgnoredChars(String text, int start, {int? end}) {
  final tokenSearchEnd = end ?? text.length;
  var index = start;
  while (index < tokenSearchEnd && index < text.length) {
    final codeUnit = text.codeUnitAt(index);
    if (codeUnit <= 32 || _tokenLeadingDelimiters.contains(text[index])) {
      index++;
      continue;
    }
    break;
  }
  return index;
}

String _trimTokenTrailingPunctuation(String token) {
  var end = token.length;
  while (end > 0 && _tokenTrailingPunctuation.contains(token[end - 1])) {
    end--;
  }
  return token.substring(0, end);
}

// Shared-text tokens may be copied from prose, quoted strings, markdown code
// spans, or angle-bracket wrappers. Keep delimiter pairs explicit so broad
// human-entered token support does not silently diverge between wrapper styles.
const _tokenLeadingDelimiters = '"\'`<';
const _tokenTrailingPunctuation = '.,;:!?)]}>"\'`';

bool _isTokenChar(int codeUnit) {
  return (codeUnit >= 0x30 && codeUnit <= 0x39) ||
      (codeUnit >= 0x41 && codeUnit <= 0x5a) ||
      (codeUnit >= 0x61 && codeUnit <= 0x7a) ||
      codeUnit == 0x2d ||
      codeUnit == 0x2e ||
      codeUnit == 0x2f ||
      codeUnit == 0x3a ||
      codeUnit == 0x3d ||
      codeUnit == 0x5f ||
      codeUnit == 0x7e ||
      codeUnit == 0x2b;
}

String? _normalizeBaseUrl(String? raw) {
  final value = navivoxOptionalLiteralStringFromJson(raw);
  if (value == null) return null;

  final uri = Uri.tryParse(value);
  if (uri == null || !uri.hasScheme) return value;
  if (uri.host.isEmpty) return null;

  final scheme = uri.scheme.toLowerCase();
  if (scheme != 'http' && scheme != 'https') return null;
  return navivoxOriginFromUri(uri);
}

String? _normalizeWebSocketUrl(String? raw) =>
    navivoxWebSocketUrlFromEndpointString(
      navivoxOptionalLiteralStringFromJson(raw),
    );

String? _normalizeBaseUrlFromWebSocketUrl(String? normalizedWebSocketUrl) =>
    navivoxHttpBaseUrlFromEndpointString(normalizedWebSocketUrl);

import '../connection_import_parser.dart';

void main() {
  parsesValidCorePairingDescriptor();
  preservesRepeatedCorePairingQueryValues();
  parsesGenericTokenUrlOutsideCoreDescriptorProtocol();
  preservesGenericUrlMetadataWhenBaseUrlComesFromUrlOrigin();
  preservesGenericUrlRepeatedQueryValuesAfterBlankCopyArtifacts();
  preservesMetadataFromUrlEmbeddedInSharedText();
  preservesWebSocketUrlEmbeddedInSharedText();
  prefersEmbeddedUrlTokenOverEarlierStaleSharedTextToken();
  prefersTokenAfterSelectedEmbeddedUrlOverEarlierStaleSharedTextToken();
  readsEarliestLabeledSharedTextTokenAfterSelectedUrl();
  prefersRicherEmbeddedUrlOverEarlierUnrelatedUrl();
  prefersLaterSharedTextUrlWhenTokenBelongsToThatUrl();
  prefersConnectionPathOverEarlierEqualRankMetadataUrl();
  doesNotLetLabelBeforeLaterSharedTextUrlConsumeThatUrlAsToken();
  doesNotUseUrlAfterSharedTextTokenLabelAsToken();
  preservesGenericWebSocketUrlImports();
  prefersCompleteJsonEntryOverEarlierPartialCandidate();
  prefersRicherJsonEntryOverEarlierMinimallyCompleteCandidate();
  doesNotPreferIncompleteMetadataEntryOverCompleteConnectionEntry();
  appliesTopLevelJsonConnectionDefaultsToEntries();
  prefersEntryOverrideWhenTopLevelJsonDefaultIsAlsoImportable();
  prefersEntryAliasOverrideOverTopLevelJsonDefaultAlias();
  doesNotLetMetadataOnlyJsonEntryStealDefaultCredentialsFromConcreteEntry();
  parsesSharedTextTokenWithSpacedSeparator();
  parsesSharedTextTokenWrappedInQuotes();
  parsesSharedTextTokenWrappedInBackticks();
  parsesSharedTextTokenWrappedInAngleBrackets();
  stripsSentenceTrailingPeriodFromSharedTextUrl();
  stripsTrailingPunctuationFromPlainCopiedUrl();
  stripsAngleBracketFromSharedTextUrl();
  stripsBacktickFromSharedTextUrl();
  rejectsMalformedCorePairingDescriptorBeforeGenericFallback();
  rejectsCorePairingDescriptorWithHttpWebSocketUrl();
  rejectsCorePairingDescriptorWithNonHttpBaseUrl();
  doesNotTreatInvalidJsonWebSocketUrlAsBaseUrl();
  doesNotTreatUnsupportedJsonBaseUrlSchemeAsBaseUrl();
}

void parsesValidCorePairingDescriptor() {
  final result = parseNavivoxConnectionImportPayload(
    'navivox://connect?websocket_url=ws%3A%2F%2F127.0.0.1%3A8765%2Fws&rest_token=nvbx_ok&server_id=srv&profile_id=profile',
  );

  _expect(result != null, 'valid navivox://connect descriptor should parse');
  _expect(
    result!.baseUrl == 'http://127.0.0.1:8765',
    'baseUrl derived from websocket_url',
  );
  _expect(
    result.webSocketUrl == 'ws://127.0.0.1:8765/ws',
    'webSocketUrl preserved',
  );
  _expect(result.token == 'nvbx_ok', 'rest_token preserved');
  _expect(result.serverId == 'srv', 'server_id preserved');
  _expect(result.profileId == 'profile', 'profile_id preserved');
}

void preservesRepeatedCorePairingQueryValues() {
  final result = parseNavivoxConnectionImportPayload(
    'navivox://connect?websocket_url=ws%3A%2F%2F127.0.0.1%3A8765%2Fws&websocket_url=&rest_token=nvbx_ok&rest_token=',
  );

  _expect(
    result != null,
    'core pairing descriptor with repeated blank copy artifacts should parse',
  );
  _expect(
    result!.webSocketUrl == 'ws://127.0.0.1:8765/ws',
    'first nonblank repeated websocket_url wins',
  );
  _expect(result.token == 'nvbx_ok', 'first nonblank repeated rest_token wins');
}

void parsesGenericTokenUrlOutsideCoreDescriptorProtocol() {
  final result = parseNavivoxConnectionImportPayload(
