  final result = parseNavivoxConnectionImportPayload(
    '{"entries":[{"base_url":"https://gateway.example","token":"nvbx_first"},{"base_url":"https://gateway.example","token":"nvbx_second"}]}',
  );

  _expect(result != null, 'JSON entries should parse');
